import { ChatFlow } from 'flowise/dist';

const validateIntermediateOutputs = (chatflow: ChatFlow, executionTrace: any[]) => {
  const jsonParseNodes = chatflow.nodes.filter(n => n.type === 'JsonParseNode');
  const failures: string[] = [];

  executionTrace.forEach(trace => {
    jsonParseNodes.forEach(node => {
      if (trace.nodeId === node.id && trace.output) {
        try {
          const parsed = JSON.parse(trace.output);
          if (!parsed.schemaVersion || typeof parsed !== 'object') {
            failures.push(`Node ${node.id}: Invalid schema in output`);
          }
        } catch (e) {
          failures.push(`Node ${node.id}: JSON parse failed`);
        }
      }
    });
  });

  return {
    valid: failures.length === 0,
    issues: failures
  };
};```

