const checkVectorRelevance = (chatflow: ChatFlow, retrievalLogs: any[]) => {
  const retrievalNodes = chatflow.nodes.filter(n => 
    n.type.includes('Retriever') || n.type.includes('VectorStore')
  );

  const lowRelevance: any[] = [];

  retrievalLogs.forEach(log => {
    if (log.similarityScores) {
      const avgScore = log.similarityScores.reduce((a: number, b: number) => a + b, 0) / log.similarityScores.length;
      if (avgScore < 0.7) {
        lowRelevance.push({
          nodeId: log.nodeId,
          avgScore,
          docsReturned: log.documents?.length || 0
        });
      }
    }
  });

  return {
    healthy: lowRelevance.length === 0,
    issues: lowRelevance
  };
};```

