const detectSilentToolFailures = (executionTrace: any[]) => {
  const toolErrors: any[] = [];

  executionTrace.forEach((trace, index) => {
    if (trace.nodeType?.includes('CustomFunction') || trace.nodeType?.includes('Tool')) {
      if (trace.error && !trace.propagated) {
        toolErrors.push({
          nodeId: trace.nodeId,
          error: trace.error.message,
          continued: executionTrace[index + 1]?.timestamp !== undefined
        });
      }
    }
  });

  return {
    clean: toolErrors.length === 0,
    silentFailures: toolErrors
  };
};```

