// Custom Validation Node for Flowise
import { Node } from 'flowise/dist';

export class OutputValidatorNode extends Node {
  constructor() {
    super();
    this.schema = {
      type: 'object',
      properties: {
        data: { type: 'object' },
        schemaVersion: { type: 'string', const: '1.0' }
      },
      required: ['data', 'schemaVersion']
    };
  }

  async validateInput(input: any): Promise<boolean> {
    try {
      const parsed = JSON.parse(input);
      return !!parsed.schemaVersion && typeof parsed.data === 'object';
    } catch {
      return false;
    }
  }
}```

