// Flowise Custom Retriever with filtering
import { VectorStoreRetriever } from 'flowise/dist';

export class FilteredRetriever extends VectorStoreRetriever {
  similarityThreshold = 0.7;

  async retrieve(query: string, k: number = 4) {
    const results = await super.retrieve(query, k * 2); // Get more, filter down
    return results.filter(doc => doc.metadata?.similarityScore >= this.similarityThreshold)
      .slice(0, k);
  }

  // Add to Flowise chatflow config
  config = {
    ...this.config,
    similarityThreshold: { value: 0.7, isRequired: true }
  };
}```

