// Flowise Chatflow Error Handler
import { ChatFlow } from 'flowise/dist';

export const withErrorPropagation = (chatflow: ChatFlow) => {
  const originalExecute = chatflow.execute;

  chatflow.execute = async (input: any) => {
    try {
      return await originalExecute.call(chatflow, input);
    } catch (error) {
      // Check if error came from custom tool
      if (error.nodeType?.includes('CustomFunction')) {
        throw new Error(`Tool failure in ${error.nodeId}: ${error.message}`);
      }
      throw error;
    }
  };

  return chatflow;
};```

