export const instrumentedChatflow = (chatflow: ChatFlow) => {
  // Capture all node executions
  chatflow.on('node:execute', (nodeId, input, output) => {
    vex.capture('flowise.node_execution', {
      chatflowId: chatflow.id,
      nodeId,
      nodeType: chatflow.nodes.find(n => n.id === nodeId)?.type,
      input: JSON.stringify(input),
      output: JSON.stringify(output),
      timestamp: Date.now()
    });
  });

  // Auto-generate tests for common Flowise failure modes
  vex.test.generate({
    framework: 'flowise',
    scenarios: ['intermediate_validation', 'vector_relevance', 'tool_errors', 'context_handoff'],
    chatflowSchema: chatflow.exportSchema()
  });

  return chatflow;
};

